  nickname?: string;
  canExportAnalytics?: boolean;
}

export interface QuickActionConfig {
  id: string;
  label: string;
  color: string;
  inputType: 'PART' | 'TEXT' | 'CUSTOMER' | 'SUPPLIER' | 'ACTIVITY';
