import React, { useState, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useLanguage } from '../LanguageContext';
import { useData } from '../../context/DataContext';
import { QuickActionConfig } from '../../types/appTypes';
import PartNumberInput from '../PartNumberInput';

const QuickActionTab: React.FC = () => {
    const { t, language } = useLanguage();
    const data = useData();

    const [activeAction, setActiveAction] = useState<QuickActionConfig | null>(null);
    const [inputValue, setInputValue] = useState('');
    const [partnerSearch, setPartnerSearch] = useState('');
    const [qty, setQty] = useState('1');
    const [isSubmitting, setIsSubmitting] = useState(false);

    // Filter and SORT partners alphabetically based on search input
    const filteredPartners = useMemo(() => {
        if (!activeAction) return [];
        const items = activeAction.inputType === 'CUSTOMER' ? data.customers : data.suppliers;

        // 1. Filtrácia
        const q = partnerSearch.toLowerCase().trim();
        const filtered = q 
            ? items.filter(i => 
                i.name.toLowerCase().includes(q) || 
                (i.description && i.description.toLowerCase().includes(q))
              )
            : [...items];

        // 2. Abecedné zoradenie (A-Z)
        return filtered.sort((a, b) => a.name.localeCompare(b.name, language === 'sk' ? 'sk' : 'en'));
    }, [activeAction, partnerSearch, data.customers, data.suppliers, language]);

    const handleActionClick = (action: QuickActionConfig) => {
        // AK IDE O ACTIVITY - Vynechávame modal a hneď ukladáme
        if (action.inputType === 'ACTIVITY') {
            handleImmediateSubmit(action);
            return;
        }

        setActiveAction(action);
        setInputValue(action.defaultText || '');
        setPartnerSearch('');
        setQty('1');
    };

    const handleClose = () => {
        setActiveAction(null);
        setInputValue('');
        setPartnerSearch('');
        setQty('1');
    };

    const handleImmediateSubmit = async (action: QuickActionConfig) => {
        setIsSubmitting(true);
        try {
            const op = data.logisticsOperations.find(o => o.id === action.logisticsOpId);
            await data.onAddTask(
                (action.defaultText || action.label).toUpperCase(),
                op?.value || 'Support Activity',
                '1',
                'pcs',
                'NORMAL',
                true,
                action.label, 
                false,
                action.sourceSectorId || op?.defaultSourceSectorId,
                action.targetSectorId || op?.defaultTargetSectorId,
                true, // startNow
                true  // isActivity
            );
            alert(language === 'sk' ? `Aktivita "${action.label}" spustená.` : `Activity "${action.label}" started.`);
        } catch (e) {
            console.error(e);
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleSubmit = async () => {
        if (!activeAction || !inputValue || !qty) {
            alert(t('fill_all_fields'));
            return;
        }

        setIsSubmitting(true);
        try {
            const op = data.logisticsOperations.find(o => o.id === activeAction.logisticsOpId);

            await data.onAddTask(
                inputValue.toUpperCase(),
                op?.value || 'LOGISTIKA',
                qty,
                'pallet',
                'NORMAL',
                true,
                activeAction.label, 
                false,
                activeAction.sourceSectorId || op?.defaultSourceSectorId,
                activeAction.targetSectorId || op?.defaultTargetSectorId,
                true, // startNow parameter
                false // isActivity
            );

            handleClose();
        } catch (e) {
            console.error(e);
            alert("Chyba pri vytváraní rýchlej akcie.");
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="max-w-7xl mx-auto space-y-8 pb-20 animate-fade-in text-slate-200">
            {/* HERO SECTION */}
            <div className="bg-slate-900 border border-slate-700 rounded-[2.5rem] p-8 shadow-2xl flex flex-col md:flex-row items-center gap-8 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-64 h-64 bg-fuchsia-500/5 rounded-full -mr-32 -mt-32 blur-3xl pointer-events-none"></div>
                <div className="w-20 h-20 bg-fuchsia-500/10 rounded-3xl flex items-center justify-center border-2 border-fuchsia-500/30 flex-shrink-0 shadow-lg">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-fuchsia-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                    </svg>
                </div>
                <div className="text-center md:text-left">
                    <h2 className="text-3xl font-black text-white uppercase tracking-tighter leading-none">{t('tab_quick_action')}</h2>
                    <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-2">Bleskové vytváranie a preberanie logistických úloh</p>
                </div>
            </div>

            {/* BUTTON GRID */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {data.quickActions.map(action => (
                    <button
                        key={action.id}
                        onClick={() => handleActionClick(action)}
                        disabled={isSubmitting}
                        className={`group relative h-44 rounded-[2rem] border-2 border-white/5 ${action.color} shadow-xl hover:scale-[1.02] active:scale-95 transition-all flex flex-col items-center justify-center p-8 text-center`}
                    >
                        <div className="absolute inset-0 bg-black opacity-0 group-hover:opacity-10 transition-opacity rounded-[2rem]"></div>
                        <span className="text-xl font-black text-white uppercase leading-tight tracking-tighter group-hover:scale-110 transition-transform drop-shadow-lg">
                            {action.label}
                        </span>
                        <div className="mt-4 flex items-center gap-2">
                             <span className="bg-white/20 px-3 py-1 rounded-full text-[9px] font-black text-white uppercase tracking-widest">
                                {data.logisticsOperations.find(o => o.id === action.logisticsOpId)?.value || 'Logistika'}
                             </span>
                             {action.inputType === 'ACTIVITY' && (
                                <span className="bg-black/40 px-2 py-0.5 rounded text-[8px] font-black text-white uppercase">Support Activity</span>
                             )}
                        </div>
                        <div className="absolute bottom-4 opacity-30 text-white group-hover:opacity-100 transition-opacity">
                            {action.inputType === 'ACTIVITY' ? (
                                <svg className="w-5 h-5 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                            ) : (
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" /></svg>
                            )}
                        </div>
                    </button>
                ))}

                {data.quickActions.length === 0 && (
                    <div className="col-span-full py-20 text-center border-2 border-dashed border-slate-800 rounded-[2.5rem] opacity-40">
                         <p className="text-slate-500 font-black uppercase tracking-[0.3em] text-xs">Žiadne definované akcie. Kontaktujte Administrátora.</p>
                    </div>
                )}
            </div>

            {/* ACTION MODAL */}
            {activeAction && createPortal(
                <div className="fixed inset-0 z-[10000] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-fade-in" onClick={handleClose}>
                    <div className="bg-slate-900 border-2 border-slate-700 rounded-[3rem] shadow-[0_0_100px_rgba(0,0,0,0.5)] w-full max-w-2xl overflow-hidden relative" onClick={e => e.stopPropagation()}>
                        <div className={`h-4 ${activeAction.color} border-b border-white/10`}></div>

                        <div className="p-8 sm:p-10 space-y-8 sm:space-y-10">
                            <div className="text-center">
                                <h3 className="text-3xl font-black text-white uppercase tracking-tighter leading-none mb-2">{activeAction.label}</h3>
                                <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Vytvoriť a spustiť úlohu</p>
                            </div>

                            <div className="space-y-8">
                                {/* DYNAMIC INPUT */}
                                <div>
                                    <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3 ml-1">
                                        {activeAction.inputType === 'PART' ? 'ČÍSLO DIELU' : 
                                         activeAction.inputType === 'CUSTOMER' ? 'VÝBER ZÁKAZNÍKA' :
                                         activeAction.inputType === 'SUPPLIER' ? 'VÝBER DODÁVATEĽA' : 'TEXTOVÁ REFERENCIA'}
                                    </label>

                                    {activeAction.inputType === 'PART' ? (
                                        <PartNumberInput 
                                            parts={Object.keys(data.partsMap)}
                                            value={inputValue}
                                            onPartSelect={(v) => setInputValue(v || '')}
                                            onInputChange={(v) => setInputValue(v.toUpperCase())}
                                            placeholder="NAPR. 3323..."
                                        />
                                    ) : activeAction.inputType === 'CUSTOMER' || activeAction.inputType === 'SUPPLIER' ? (
                                        <div className="space-y-4">
                                            <div className="relative">
                                                <input 
                                                    type="text"
                                                    value={partnerSearch}
                                                    onChange={e => setPartnerSearch(e.target.value.toUpperCase())}
                                                    placeholder="HĽADAŤ V ZOZNAME..."
                                                    className="w-full h-12 bg-slate-950 border-2 border-slate-800 rounded-xl px-4 pl-12 text-white font-bold uppercase focus:border-fuchsia-500 outline-none transition-all"
                                                    autoFocus
                                                />
                                                <svg className="absolute left-4 top-3.5 h-5 w-5 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                                            </div>

                                            <div className="max-h-[300px] overflow-y-auto custom-scrollbar border-2 border-slate-800 rounded-2xl bg-slate-950 p-2 space-y-1">
                                                {filteredPartners.map(item => (
                                                    <button
                                                        key={item.id}
                                                        onClick={() => setInputValue(item.name)}
                                                        className={`w-full py-5 px-6 rounded-xl font-black uppercase text-sm transition-all text-left flex items-center justify-between border-2 ${inputValue === item.name ? `text-white ${activeAction.color} border-white/20 shadow-lg scale-[1.02]` : 'bg-slate-900 text-white border-white/5 hover:bg-slate-800 hover:border-white/10'}`}
                                                    >
                                                        <span className="truncate">{item.name}</span>
                                                        {inputValue === item.name && <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" /></svg>}
                                                    </button>
                                                ))}
                                                {filteredPartners.length === 0 && (
                                                    <div className="py-10 text-center opacity-30">
                                                        <p className="text-xs font-black uppercase tracking-widest">Nič sa nenašlo</p>
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    ) : (
                                        <input 
                                            value={inputValue} 
                                            onChange={e => setInputValue(e.target.value.toUpperCase())}
                                            className="w-full h-16 bg-slate-950 border-2 border-slate-800 rounded-2xl px-6 text-white font-black uppercase text-xl focus:border-fuchsia-500 outline-none transition-all shadow-inner"
                                            placeholder="..."
                                            autoFocus
                                        />
                                    )}
                                </div>

                                {/* QUANTITY */}
                                <div>
                                    <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3 ml-1">POČET PALIET</label>
                                    <div className="flex gap-4">
                                        {[1, 2, 3, 4, 5].map(n => (
                                            <button 
                                                key={n} 
                                                onClick={() => setQty(String(n))}
                                                className={`flex-1 h-14 rounded-xl font-black text-xl transition-all border-2 ${qty === String(n) ? 'bg-fuchsia-600 border-fuchsia-500 text-white shadow-lg' : 'bg-slate-800 border-slate-700 text-slate-500 hover:text-slate-300'}`}
                                            >
                                                {n}
                                            </button>
                                        ))}
                                        <input 
                                            type="number"
                                            value={qty}
                                            onChange={e => setQty(e.target.value)}
                                            className="w-20 h-14 bg-slate-950 border-2 border-slate-800 rounded-xl px-2 text-center text-white font-black text-xl focus:border-fuchsia-500 outline-none"
                                            placeholder="+"
                                        />
                                    </div>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-4 pt-6">
                                <button 
                                    onClick={handleClose}
                                    className="h-16 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all active:scale-95"
                                >
                                    ZRUŠIŤ
                                </button>
                                <button 
                                    onClick={handleSubmit}
                                    disabled={isSubmitting || !inputValue}
                                    className={`h-16 ${activeAction.color} hover:brightness-110 disabled:opacity-30 text-white rounded-2xl font-black uppercase text-sm tracking-[0.2em] border-b-4 border-black/30 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3`}
                                >
                                    {isSubmitting ? '...' : <><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg> ODOSLAŤ A SPUSTIŤ</>}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default QuickActionTab;

import { useState, useEffect, useRef, useCallback } from 'react';
import { db } from '../../firebase';
import { collection, onSnapshot, query, where, limit, doc, getDocs } from 'firebase/firestore';
import { Task, PriorityLevel, Notification, ScrapConfig, DBItem } from '../../types/appTypes';
import { PRIORITY_ORDER } from '../../constants/uiConstants';
import { taskService } from '../../services/taskService';

export const useTaskData = (
    isAuthenticated: boolean, 
    checkPermission: (perm: string) => boolean,
    onAddNotification: (n: Partial<Notification>) => void,
    scrapConfig?: ScrapConfig,
    logisticsOperations?: DBItem[]
) => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [draftTasks, setDraftTasks] = useState<Task[]>([]);
  const isFirstLoad = useRef(true);
  const checkPermissionRef = useRef(checkPermission);

  useEffect(() => { checkPermissionRef.current = checkPermission; }, [checkPermission]);

  // 1. LISTENER PRE ŽIVÉ ÚLOHY
  useEffect(() => {
    if (!isAuthenticated) return;
    const threshold = Date.now() - (3 * 24 * 60 * 60 * 1000);
    const q = query(collection(db, 'tasks'), where('createdAt', '>=', threshold), limit(300)); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));

      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added' && checkPermissionRef.current('perm_play_sound')) {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3').play().catch(() => {});
                  }
              }
          });
      }
      isFirstLoad.current = false;

      setTasks(newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) return (b.completedAt || 0) - (a.completedAt || 0);
        if (a.isManualBlocked !== b.isManualBlocked) return (a.isManualBlocked ? 1 : 0) - (b.isManualBlocked ? 1 : 0);
        const pA = PRIORITY_ORDER[a.priority || 'NORMAL'], pB = PRIORITY_ORDER[b.priority || 'NORMAL'];
        return pA !== pB ? pA - pB : (a.createdAt || 0) - (b.createdAt || 0);
      }));
    });
  }, [isAuthenticated]);

  // 2. LISTENER PRE DRAFT
  useEffect(() => {
    return onSnapshot(doc(db, 'settings', 'draft'), (s) => {
      setDraftTasks(s.exists() ? (s.data().data || []) : []);
    });
  }, []);

  // 3. WRAPPERS PRE SERVICE
  const onAddTask = useCallback(async (
    pn: string, wp: string | null, qty: string, unit: string, prio: PriorityLevel, 
    isLog?: boolean, note?: string, isProd?: boolean, src?: string | null, tgt?: string | null,
    startNow?: boolean, isAct?: boolean
  ) => {
    const user = localStorage.getItem('app_user') || 'Unknown';

    let finalWorkplace = wp || '';
    let finalSource = src || null;
    let finalTarget = tgt || null;
    let finalIsLog = !!isLog;
    let finalIsProd = !!isProd;

    // Špeciálne ošetrenie pre šrot (Scrap)
    if (pn === "Váženie šrotu") {
        finalIsLog = true;
        finalIsProd = false; 

        if (scrapConfig?.scrapLogisticsOpId && logisticsOperations) {
            const foundOp = logisticsOperations.find(o => o.id === scrapConfig.scrapLogisticsOpId);
            if (foundOp) {
                finalWorkplace = foundOp.value;
                finalSource = foundOp.defaultSourceSectorId || null;
                finalTarget = foundOp.defaultTargetSectorId || null;
            }
        }
    }

    const taskData: any = {
        partNumber: pn || '',
        text: pn || '',
        workplace: finalWorkplace,
        quantity: qty || '0',
        quantityUnit: unit || 'pcs',
        priority: prio || 'NORMAL',
        isLogistics: finalIsLog,
        isProduction: finalIsProd,
        isActivity: !!isAct,
        createdBy: user,
        note: note || '',
        plate: finalIsLog ? (note || '') : '',
        sourceSectorId: finalSource,
        targetSectorId: finalTarget
    };

    // OKAMŽITÉ SPUSTENIE (Rýchle akcie / Inventúra / Šrot)
    if (startNow || pn === "Počítanie zásob" || pn === "Váženie šrotu") {
        taskData.isInProgress = true;
        taskData.inProgressBy = user;
        taskData.startedAt = Date.now();
    }

    return taskService.addTask(taskData);
  }, [scrapConfig, logisticsOperations]);

  const onUpdateTask = useCallback((id: string, up: Partial<Task>) => taskService.updateTask(id, up), []);
  const onDeleteTask = useCallback((id: string) => taskService.deleteTask(id), []);

  const onToggleTask = useCallback(async (id: string, sectorId?: string) => {
      const task = tasks.find(t => t.id === id);
      if (!task) return;
      const user = localStorage.getItem('app_user') || 'Unknown';
      const updates: any = { isDone: !task.isDone, completedAt: !task.isDone ? Date.now() : null, completedBy: !task.isDone ? user : null, status: !task.isDone ? 'completed' : 'open' };
      if (!task.isDone && sectorId) updates.pickedFromSectorId = sectorId;
      return taskService.updateTask(id, updates);
  }, [tasks]);

  const onToggleMissing = useCallback(async (id: string, reason?: string) => {
      const task = tasks.find(t => t.id === id);
      if (!task) return;
      const user = localStorage.getItem('app_user') || 'Unknown';
      const isMarking = !task.isMissing;
      const updates: any = { isMissing: isMarking, missingReason: isMarking ? (reason || 'Unknown') : null, missingReportedBy: isMarking ? user : null, isInProgress: false, inProgressBy: null };
      if (isMarking && task.createdBy) {
          onAddNotification({ partNumber: task.partNumber, reason: `CHÝBA: ${reason}`, reportedBy: user, targetUser: task.createdBy });
      }
      return taskService.updateTask(id, updates);
  }, [tasks, onAddNotification]);

  const onSetInProgress = useCallback(async (id: string) => {
      const task = tasks.find(t => t.id === id);
      if (!task) return;
      const user = localStorage.getItem('app_user') || 'Unknown';
      return taskService.updateTask(id, task.isInProgress ? { isInProgress: false, inProgressBy: null } : { isInProgress: true, inProgressBy: user, startedAt: Date.now() });
  }, [tasks]);

  const onToggleBlock = useCallback(async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    const user = localStorage.getItem('app_user') || 'Unknown';
    const isCurrentlyBlocked = !!task.isBlocked;
    return taskService.updateTask(id, {
        isBlocked: !isCurrentlyBlocked,
        blockedBy: !isCurrentlyBlocked ? user : null
    });
  }, [tasks]);

  const onExhaustSearch = useCallback(async (id: string) => {
    const user = localStorage.getItem('app_user') || 'Unknown';
    return taskService.updateTask(id, {
        searchExhausted: true,
        searchedBy: user
    });
  }, []);

  const onAddNote = useCallback(async (id: string, note: string) => {
    return taskService.updateTask(id, { note });
  }, []);

  const onMarkAsIncorrect = useCallback(async (id: string) => {
    const user = localStorage.getItem('app_user') || 'Unknown';
    return taskService.updateTask(id, {
        isDone: true,
        status: 'incorrectly_entered',
        completedAt: Date.now(),
        completedBy: user,
        isInProgress: false,
        inProgressBy: null
    });
  }, []);

  const onStartAudit = useCallback((id: string) => taskService.updateTask(id, { isAuditInProgress: true, auditBy: localStorage.getItem('app_user'), isInProgress: false, inProgressBy: null }), []);
  const onFinishAudit = useCallback((id: string, res: 'found' | 'missing', note: string) => {
      const task = tasks.find(t => t.id === id);
      if (task) taskService.finishAudit(task, res, note, localStorage.getItem('app_user') || 'Unknown', onAddNotification);
  }, [tasks, onAddNotification]);

  return {
    tasks, draftTasks, onAddTask, onUpdateTask, onDeleteTask, onToggleTask, onToggleMissing, onSetInProgress, onStartAudit, onFinishAudit, onToggleBlock, onExhaustSearch, onAddNote, onMarkAsIncorrect,
    onToggleManualBlock: (id: string) => { const t = tasks.find(x => x.id === id); if(t) taskService.toggleManualBlock(t); },
    onDailyClosing: taskService.dailyClosing, onWeeklyClosing: taskService.weeklyClosing,
    fetchSanons: async () => (await getDocs(collection(db, 'sanony'))).docs.map(d => d.data())
  };
};

import React from 'react';
import { Task, PriorityLevel, DBItem } from '../../../types/appTypes';
import { useLanguage } from '../../LanguageContext';
import TaskBadges from './TaskBadges';
import TaskActions from './TaskActions';

interface TaskCardProps {
  task: Task;
  currentUserName: string;
  isSystemInventoryTask: boolean;
  copiedId: string | null;
  hasPermission: (perm: string) => boolean;
  onSetInProgress: (id: string) => void;
  onToggleTask: (id: string) => void;
  onToggleBlock: (id: string) => void;
  onToggleManualBlock: (id: string) => void;
  onExhaustSearch: (id: string) => void;
  onMarkAsIncorrect: (id: string) => void;
  handleMissingClick: (task: Task, e: React.MouseEvent) => void;
  handleNoteClick: (task: Task) => void;
  handleDeleteClick: (id: string) => void;
  handleDeleteNoteClick?: (id: string) => void;
  handleCopyPart: (id: string, text: string) => void;
  openPriorityModal: (task: Task) => void;
  onAuditPart?: (task: Task) => void;
  resolveName: (username?: string | null) => string;
}

const SearchIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" /></svg>
);

const UserIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
    </svg>
);

const TaskCard: React.FC<TaskCardProps> = (props) => {
  const { t, language } = useLanguage();
  const { task, resolveName } = props;

  const isSearchingMode = !!task.isBlocked;
  const isManualBlocked = !!task.isManualBlocked;
  const isAuditInProgress = !!task.isAuditInProgress;
  const isUrgent = task.priority === 'URGENT' && !task.isDone;
  const isNoteLockedByAudit = !!(task.auditFinalBadge && !props.hasPermission('perm_btn_audit'));

  // --- SMART TIME LOGIC ---
  const formatTime = (ts?: number) => {
    if (!ts) return '';
    const now = Date.now();
    const diff = now - ts;

    if (diff < 60000) return language === 'sk' ? 'Práve teraz' : 'Just now';

    const date = new Date(ts);
    const today = new Date();
    const isToday = date.toDateString() === today.toDateString();

    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);
    const isYesterday = date.toDateString() === yesterday.toDateString();

    const timeStr = date.toLocaleTimeString(language === 'sk' ? 'sk-SK' : 'en-US', { hour: '2-digit', minute: '2-digit' });

    if (isToday) return (language === 'sk' ? 'Dnes, ' : 'Today, ') + timeStr;
    if (isYesterday) return (language === 'sk' ? 'Včera, ' : 'Yesterday, ') + timeStr;

    return date.toLocaleDateString(language === 'sk' ? 'sk-SK' : 'en-US', { day: '2-digit', month: '2-digit' }) + ', ' + timeStr;
  };

  let bgClass = "";
  let borderClass = "";
  let textClass = "text-white";

  if (task.isDone) {
    bgClass = "bg-gray-800 opacity-60";
    textClass = "text-gray-500 line-through";
  } else {
    if (isManualBlocked) { bgClass = "bg-black"; textClass = "text-gray-500"; borderClass = "border-l-4 border-gray-800"; }
    else if (isAuditInProgress) { bgClass = "bg-amber-500/20"; borderClass = "border-l-4 border-amber-500"; }
    else if (isSearchingMode) { bgClass = "bg-gray-800"; borderClass = "border-l-4 border-gray-600 shadow-inner"; }
    else if (props.isSystemInventoryTask) { bgClass = "bg-[#4169E1]/20"; borderClass = "border-l-4 border-[#4169E1]"; }
    else if (task.isInProgress) { bgClass = "bg-[#FFD700]/20"; borderClass = "border-l-4 border-[#FFD700]"; }
    else if (task.isActivity) { bgClass = "bg-indigo-900/20"; borderClass = "border-l-4 border-indigo-500"; }
    else if (task.isMissing) { bgClass = "bg-red-900/20"; borderClass = "border-l-4 border-red-500"; }
    else if (task.isLogistics) { bgClass = "bg-sky-900/10"; borderClass = "border-l-4 border-sky-500"; }
    else {
      switch (task.priority) {
        case 'URGENT': bgClass = "bg-[#FF8C00]/20"; borderClass = "border-l-4 border-[#FF8C00]"; break;
        case 'LOW': bgClass = "bg-[#1E90FF]/20"; borderClass = "border-l-4 border-[#1E90FF]"; break;
        case 'NORMAL':
        default: bgClass = "bg-[#8A2BE2]/20"; borderClass = "border-l-4 border-[#8A2BE2]"; break;
      }
    }
  }

  const renderFormattedText = (text: string | undefined, isLarge: boolean = true) => {
    if (!text) return null;
    if (!text.includes(';')) return text;
    const parts = text.split(';');
    return parts.map((part, index) => (
      <React.Fragment key={index}>
        {part.trim()}
        {index < parts.length - 1 && (
          <span className={`mx-2 text-teal-500/40 font-light inline-block transform ${isLarge ? 'scale-110 translate-y-[-1px]' : 'scale-90'}`}>→</span>
        )}
      </React.Fragment>
    ));
  };

  const getUnitLabel = (count: number, unit: string, isInventory: boolean) => {
    if (isInventory) return "pol.";
    let key = count === 1 ? `unit_${unit}_1` : (language === 'sk' && count >= 2 && count <= 4 ? `unit_${unit}_2_4` : `unit_${unit}_5`);
    return t(key as any) || unit;
  };

  const qtyNum = parseFloat(task.quantity || '0');
  const unitLabel = getUnitLabel(qtyNum, task.quantityUnit || '', props.isSystemInventoryTask);

  return (
    <div className={`group relative flex flex-col sm:flex-row rounded-lg shadow-md overflow-hidden transition-all duration-200 items-stretch ${bgClass} ${borderClass} ${!task.isDone ? 'hover:shadow-lg' : ''}`}>
      {isUrgent && !isManualBlocked && <div className="absolute left-0 top-0 bottom-0 w-1 bg-[#FF8C00] animate-pulse z-50"></div>}

      {isSearchingMode && !task.isDone && (
        <div className="absolute right-20 top-1/2 -translate-y-1/2 pointer-events-none opacity-10">
          <SearchIcon className="w-32 h-32 text-gray-400" />
        </div>
      )}

      <div className="flex-grow p-4 flex flex-col gap-1 min-w-0 relative">
        <div className="relative z-10">

          <div className="mb-2">
             <div className="flex flex-wrap gap-2">
                {task.auditFinalBadge && (
                    <span className="bg-amber-600 text-white text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded border border-amber-500 shadow-sm inline-block">
                        📌 {task.auditFinalBadge}
                    </span>
                )}
                <TaskBadges 
                    task={task} 
                    isSystemInventoryTask={props.isSystemInventoryTask} 
                    isAuditInProgress={isAuditInProgress} 
                    isSearchingMode={isSearchingMode} 
                    isManualBlocked={isManualBlocked} 
                    isUrgent={isUrgent} 
                    resolveName={resolveName}
                />
             </div>
          </div>

          <div className="flex justify-between items-start gap-3 mt-1">
            <div className="flex flex-col min-w-0">
                <h3 
                className={`text-2xl sm:text-3xl font-bold break-words whitespace-normal leading-tight cursor-copy active:scale-[0.98] transition-transform ${textClass}`}
                onClick={() => props.handleCopyPart(task.id, task.partNumber || '')}
                title={language === 'sk' ? "Kliknite pre kopírovanie" : "Click to copy"}
                >
                {renderFormattedText(task.partNumber || task.text)}
                {props.copiedId === task.id && (
                    <span className="ml-2 text-xs bg-green-600 text-white px-1.5 py-0.5 rounded-full animate-bounce inline-block font-sans lowercase align-middle">
                    {t('copied_msg')}
                    </span>
                )}
                </h3>
            </div>
            <div className="flex flex-col items-end flex-shrink-0">
              <span className={`bg-black border border-gray-700 shadow-inner px-3 py-1 rounded-full text-xl font-bold ${textClass}`}>{task.quantity || "0"} <span className="ml-1 text-lg font-normal">{unitLabel}</span></span>
            </div>
          </div>

          <div className="flex flex-wrap gap-2 items-center mt-1">
            <span className={`text-lg font-bold uppercase tracking-wider ${task.isDone ? 'text-gray-600' : isManualBlocked ? 'text-gray-600' : (task.isInProgress && !props.isSystemInventoryTask) ? 'text-[#FFD700]' : task.isActivity ? 'text-indigo-400' : props.isSystemInventoryTask ? 'text-[#4169E1]' : isAuditInProgress ? 'text-amber-500' : 'text-cyan-400'}`}>{task.workplace || "---"}</span>
            {task.note && <span className="inline-block px-2 py-0.5 rounded bg-[#fef9c3] text-gray-800 text-xs font-bold shadow-sm border border-yellow-200 leading-tight">{task.note}</span>}
          </div>

          {/* NOVÁ SEKICA: INFO O POUŽÍVATEĽOCH A ČASE */}
          <div className="flex flex-wrap items-center gap-x-4 gap-y-1 mt-3 pt-3 border-t border-white/5 opacity-80">
              <div className="flex items-center gap-1.5">
                  <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">{language === 'sk' ? 'ZADAL:' : 'CREATED:'}</span>
                  <span className="text-[10px] font-bold text-teal-400 uppercase">{resolveName(task.createdBy)}</span>
                  <span className="text-[10px] font-mono text-slate-500">{formatTime(task.createdAt)}</span>
              </div>

              {task.isDone && (
                  <div className="flex items-center gap-1.5 sm:border-l sm:border-slate-700 sm:pl-4">
                      <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">{language === 'sk' ? 'VYBAVIL:' : 'DONE BY:'}</span>
                      <span className="text-[10px] font-bold text-green-500 uppercase">{resolveName(task.completedBy)}</span>
                      <span className="text-[10px] font-mono text-slate-500">{formatTime(task.completedAt)}</span>
                  </div>
              )}
          </div>

        </div>
      </div>

      <div className="flex flex-shrink-0 items-center justify-center p-3 z-10">
        <TaskActions 
          task={task} 
          isSystemInventoryTask={props.isSystemInventoryTask} 
          isSearchingMode={isSearchingMode} 
          isManualBlocked={isManualBlocked} 
          isAuditInProgress={isAuditInProgress} 
          isNoteLockedByAudit={isNoteLockedByAudit} 
          copiedId={props.copiedId} 
          hasPermission={props.hasPermission} 
          onSetInProgress={props.onSetInProgress} 
          onToggleTask={props.onToggleTask} 
          onToggleBlock={props.onToggleBlock} 
          onToggleManualBlock={props.onToggleManualBlock} 
          onExhaustSearch={props.onExhaustSearch}
          onMarkAsIncorrect={props.onMarkAsIncorrect} 
          handleMissingClick={props.handleMissingClick} 
          handleNoteClick={props.handleNoteClick} 
          handleDeleteClick={props.handleDeleteClick} 
          handleCopyPart={props.handleCopyPart} 
          openPriorityModal={props.openPriorityModal} 
          onAuditPart={props.onAuditPart} 
        />
      </div>
    </div>
  );
};

