                    <span className="bg-amber-600 text-white text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded border border-amber-500 shadow-sm inline-block">
                        📌 {task.auditFinalBadge}
                    </span>
                )}
                <TaskBadges 
                    task={task} 
